&apos;); count++; if (item.category)&#123; item.category.forEach(function(category, next)&#123; var name = category._; switch (category.$.domain)&#123; case &apos;category&apos;: categories.push(name); break; case &apos;post_tag&apos;: tags.push(name); break; &#125; &#125;); &#125; var data = &#123; title: title || slug, id: +id, date: date, content: content, layout: status === &apos;draft&apos; ? &apos;draft&apos; : &apos;post&apos;, &#125;; if (type === &apos;page&apos;) data.layout = &apos;page&apos;; if (slug) data.slug = slug.toString(); if (comment === &apos;closed&apos;) data.comment = false; if (categories.length &amp;&amp; type === &apos;post&apos;) data.categories = categories; if (tags.length &amp;&amp; type === &apos;post&apos;) data.tags = tags; log.i(&apos;%s found: %s&apos;, captialize(type), title); data.title = data.title.toString(); data.date = data.date.toString(); //console.log(data.slug); //console.log(data.date); post.create(data, next); &#125;, function(err)&#123; if (err) return next(err); log.i(&apos;%d posts migrated.&apos;, count); &#125;); &#125; ], callback);&#125;); 最后再导入wp的数据。 12cd bloghexo migrate wordpress ../zouhongzhao.wordpress.2018-03-06.xml 耐心等待，不报错的话 就是大吉大利。 六,生成静态文件1hexo clean &amp; hexo generate —debug 加debug是为了看调试信息，看命令是否在工作。不然一等十几分钟终端没任务提示，还以为系统卡死了。 如果没报错的话，那就是万幸。 友情提醒下：这个-debug的输出信息并不能准确的告诉你是哪个文件出错了。我就被坑了，以为是hexo核心文件的问题损坏了，重装了几次。其实不是，多半是post文件有问题。打开 node_modules/hexo/lib/extend/tag.js搜索 env.renderString(str, options, (err, result)在里面加上console.log(str); 123456console.log(str);env.renderString(str, options, (err, result) =&gt; &#123; if (err) &#123; console.log(str); return reject(err); &#125; 这样的信息才是最准确的。你根据这个str的内容 搜索关键字 找到post文件 再检查 就知道了。 七，安装next主题见https://github.com/ahonn/hexo-theme-even 过程不表，很简单。完事后。打开项目的_config.yml文件，把theme改成next就行。 在hexo g下就ok了。 主题的使用说明。见http://theme-next.iissnan.com/。非常全面，该有的都有。 八，各种插件见http://theme-next.iissnan.com/我装的有 评论系统: 来必力 搜索: Algolia git自动提交: npm install hexo-deployer-git --save 七牛: https://github.com/gyk001/hexo-qiniu-sync cdn: https://github.com/zqjimlove/hexo-cdnify (将本地的js/css/images的url加入http://cdn.mallol.cn前缀。 九，nginx配置生成的静态文件一般放在public下，我的是/home/www/hexoblog/blog/public直接在nginx里指定改目录即可 1234567891011121314server &#123; listen 80; server_name blog.mallol.cn; root /home/www/hexoblog/blog/public; index index.html index.htm default.html default.htm; location ~ .*\.(gif|jpg|jpeg|png|bmp|swf)$ &#123; expires 30d; &#125; location ~ .*\.(js|css)?$ &#123; expires 12h; &#125;&#125; 十，git配置我文章很多，有400多篇。在服务器里直接hexo generate的话，要等20分钟，太尼玛慢了，搞得服务器很卡。没办法，我只好把代码下载到本地电脑上。在本地电脑里hexo generate后，把最新生成的public文件push到服务器。 所以我在ubuntu服务器里配置了git。1，创建git用户，在/home/git里mkdir blog.git 1git init &amp;&amp; git config --bool core.bare true 2,在服务器项目路径下 1234cd /home/www/hexoblog/blog/publicgit init &amp;&amp; git add . &amp;&amp; git commit -agit remote add origin /home/git/blog.gitgit push origin master 3,本地电脑里也安装git，但是不需要git init这些，因为hexo已经帮你做好了。hexo deploy这个命令就是push到服务器的所以只需要在项目_config.yml里定义。找到deploy 1234deploy: type: git repo: git@ip:/home/git/blog.git branch: master 这样就行了。比如，在本地电脑的blog目录下执行hexo d会提示你输入git密码。 hexo-deploy hexo-deploy 这样就成功push到服务器了。 提示下：你们可能会跟我显示不一样，我装了七牛，以及设置了git hooks。git hooks就是当push到git服务器后，git服务器会自动更新/home/www/hexoblog/blog/public的内容。就不需要我手动登陆服务器再pull了。 十一，一些常见的错误WARN No layout: index.html这个是没有在_config.yml定义主题，或者说themes下不存在_config.yml里的主题 title [object Object]这个是hexo的文件有损坏了，需要重新init blog，再migrate和generate 好了，核心的东西就这些了。这些基本上就够你折腾了。 十二，心得体会hexo目前最大的缺点就是hexo generate太慢太慢了，我400篇文章，耗时20分钟才搞完。可能是我开启了category和tags的原因。 优点也很明显，极客风，自由配置，全命令行操作，简单粗暴，逼格高。本地sublime text写文章比在网站后台写文章要好太多了，在线写的话 文章太长 经常会卡死。 原地址：http://blog.mallol.cn/2018/ffde19de.html
